using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

Person? deserialized = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Deserialized: {deserialized}");

// 2) TryGetTypeInfo<T>() — probe without throwing
//    Person should resolve fine:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? tryInfo))
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded → {tryInfo!.Type.Name}");
else
    Console.WriteLine("\nTryGetTypeInfo<Person> returned false");

//    Use a custom resolver that resolves nothing, so TryGetTypeInfo returns false:
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers = { (ti) => throw new NotSupportedException() }
    }
};

if (empty.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
    Console.WriteLine($"TryGetTypeInfo<Person> (empty resolver) succeeded → {missing!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> (empty resolver) returned false — no exception thrown");

public record Person(string Name, int Age);

